import json
import os
import secrets
from collections import Counter, defaultdict

import numpy as np
from PIL import Image
from flask import Flask, request, jsonify

# --- Dummy ML Model (for demonstration) ---
# In a real system, you'd use scikit-learn, TensorFlow, PyTorch, etc.
class DummyModel:
    def __init__(self):
        self.trained_data = []

    def train(self, X, y):
        # Store the training data for a dummy "prediction"
        self.trained_data = list(zip(X, y))
        print(f"Dummy model trained on {len(X)} samples.")

    def predict(self, X):
        # Dummy prediction: just return the label if it was in training data,
        # otherwise return a default or random label.
        predictions = []
        for img_data in X:
            found = False
            for trained_img_data, trained_label in self.trained_data:
                # In a real model, this would be feature comparison
                if np.array_equal(img_data, trained_img_data):
                    predictions.append(trained_label)
                    found = True
                    break
            if not found:
                predictions.append("unknown") # Default for unseen data
        return predictions

# --- Configuration ---
UPLOAD_FOLDER = 'uploads'
LABELS_FILE = 'labels.json'
IMAGE_METADATA_FILE = 'image_metadata.json'
MIN_ANNOTATORS_PER_IMAGE = 3 # Minimum annotations required for majority vote
app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Ensure upload directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# --- Data Structures ---
# image_metadata: { image_id: { 'filename': '...', 'status': 'pending'/'labeled', 'hash': '...' } }
image_metadata = {}

# labels_data: { image_id: [ { 'annotator_id': '...', 'label': '...', 'timestamp': '...' } ] }
labels_data = defaultdict(list)

# labeled_dataset: { image_id: 'agreed_label' }
labeled_dataset = {}

# --- Model Instance ---
model = DummyModel()

# --- Helper Functions ---
def save_data():
    with open(LABELS_FILE, 'w') as f:
        json.dump(labels_data, f, indent=4)
    with open(IMAGE_METADATA_FILE, 'w') as f:
        json.dump(image_metadata, f, indent=4)

def load_data():
    global image_metadata, labels_data, labeled_dataset
    if os.path.exists(LABELS_FILE):
        with open(LABELS_FILE, 'r') as f:
            labels_data_raw = json.load(f)
            labels_data = defaultdict(list, labels_data_raw)
    if os.path.exists(IMAGE_METADATA_FILE):
        with open(IMAGE_METADATA_FILE, 'r') as f:
            image_metadata = json.load(f)

    # Rebuild labeled_dataset from loaded labels_data
    re_aggregate_labels()
    # Retrain model if there are aggregated labels
    if labeled_dataset:
        train_model_on_aggregated_data()

def generate_id():
    return secrets.token_urlsafe(16)

def get_image_path(image_id):
    if image_id in image_metadata:
        return os.path.join(app.config['UPLOAD_FOLDER'], image_metadata[image_id]['filename'])
    return None

def aggregate_labels(image_id):
    if image_id not in labels_data or len(labels_data[image_id]) < MIN_ANNOTATORS_PER_IMAGE:
        return None

    annotations = [ann['label'] for ann in labels_data[image_id]]
    if not annotations:
        return None

    # Majority voting
    label_counts = Counter(annotations)
    most_common = label_counts.most_common(1)

    if not most_common:
        return None

    agreed_label, count = most_common[0]

    # Simple majority: if count > total_annotations / 2
    if count > len(annotations) / 2:
        return agreed_label
    # If there's a tie for the most common, it's not a clear majority.
    # For simplicity, we'll just take the first one returned by most_common.
    # In a real system, you might have more sophisticated tie-breaking or
    # require more annotations.
    return agreed_label


def re_aggregate_labels():
    global labeled_dataset
    labeled_dataset = {}
    for image_id in image_metadata:
        if image_metadata[image_id]['status'] == 'pending':
            agreed_label = aggregate_labels(image_id)
            if agreed_label:
                labeled_dataset[image_id] = agreed_label
                image_metadata[image_id]['status'] = 'labeled'
    print(f"Aggregated {len(labeled_dataset)} images.")
    save_data() # Save updated status

def train_model_on_aggregated_data():
    X_train = []
    y_train = []
    for image_id, label in labeled_dataset.items():
        image_path = get_image_path(image_id)
        if image_path and os.path.exists(image_path):
            try:
                # For dummy model, load image as a flat numpy array (grayscale)
                img = Image.open(image_path).convert('L') # Convert to grayscale
                img_array = np.array(img).flatten()
                X_train.append(img_array)
                y_train.append(label)
            except Exception as e:
                print(f"Error loading image {image_path} for training: {e}")
    if X_train:
        model.train(X_train, y_train)
    else:
        print("No aggregated data to train the model.")

# Load data on startup
load_data()

# --- API Endpoints ---

@app.route('/upload_image', methods=['POST'])
def upload_image():
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400

    file = request.files['image']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file:
        image_id = generate_id()
        filename = f"{image_id}_{file.filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)

        # In a real system, calculate a hash of the image content
        # to prevent duplicate uploads. For now, we'll use filename.
        image_metadata[image_id] = {
            'filename': filename,
            'status': 'pending',
            'hash': 'dummy_hash' # Replace with actual hash
        }
        save_data()
        return jsonify({
            'message': 'Image uploaded successfully',
            'image_id': image_id,
            'image_url': f'/image/{image_id}'
        }), 201

@app.route('/image/<image_id>')
def get_image(image_id):
    if image_id not in image_metadata:
        return jsonify({'error': 'Image not found'}), 404
    return app.send_from_directory(app.config['UPLOAD_FOLDER'], image_metadata[image_id]['filename'])

@app.route('/annotate', methods=['POST'])
def annotate_image():
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid JSON'}), 400

    image_id = data.get('image_id')
    label = data.get('label')
    annotator_id = data.get('annotator_id')

    if not all([image_id, label, annotator_id]):
        return jsonify({'error': 'Missing image_id, label, or annotator_id'}), 400

    if image_id not in image_metadata:
        return jsonify({'error': 'Image not found'}), 404

    # Prevent annotator from labeling the same image multiple times
    for existing_annotation in labels_data[image_id]:
        if existing_annotation['annotator_id'] == annotator_id:
            return jsonify({'error': 'Annotator already labeled this image'}), 409

    annotation = {
        'annotator_id': annotator_id,
        'label': label,
        'timestamp': os.system('date +"%Y-%m-%d %H:%M:%S"') # Use actual timestamp in production
    }
    labels_data[image_id].append(annotation)
    save_data()

    # Attempt to aggregate and train if enough annotations are received
    agreed_label = aggregate_labels(image_id)
    if agreed_label and image_metadata[image_id]['status'] == 'pending':
        labeled_dataset[image_id] = agreed_label
        image_metadata[image_id]['status'] = 'labeled'
        save_data() # Save updated status
        train_model_on_aggregated_data()
        return jsonify({
            'message': 'Annotation submitted, image labeled and model retrained!',
            'image_id': image_id,
            'agreed_label': agreed_label
        }), 200
    elif agreed_label:
        return jsonify({
            'message': 'Annotation submitted, image already labeled.',
            'image_id': image_id,
            'agreed_label': agreed_label
        }), 200
    else:
        return jsonify({
            'message': 'Annotation submitted, awaiting more annotations.',
            'image_id': image_id,
            'current_annotations': len(labels_data[image_id]),
            'required_annotations': MIN_ANNOTATORS_PER_IMAGE
        }), 200

@app.route('/status/<image_id>', methods=['GET'])
def get_image_status(image_id):
    if image_id not in image_metadata:
        return jsonify({'error': 'Image not found'}), 404

    status = image_metadata[image_id]['status']
    current_annotations = len(labels_data[image_id])
    agreed_label = labeled_dataset.get(image_id)

    response = {
        'image_id': image_id,
        'status': status,
        'annotations_received': current_annotations,
        'annotations_required': MIN_ANNOTATORS_PER_IMAGE,
    }
    if agreed_label:
        response['agreed_label'] = agreed_label
    return jsonify(response), 200

@app.route('/dataset', methods=['GET'])
def get_dataset():
    # Return the aggregated labeled dataset
    return jsonify(labeled_dataset), 200

@app.route('/predict', methods=['POST'])
def predict_label():
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400

    file = request.files['image']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file:
        try:
            # Load the image for prediction
            img = Image.open(file).convert('L')
            img_array = np.array(img).flatten()
            prediction = model.predict([img_array])
            return jsonify({'prediction': prediction[0]}), 200
        except Exception as e:
            return jsonify({'error': f'Error processing image for prediction: {e}'}), 500

@app.route('/metrics', methods=['GET'])
def get_metrics():
    total_images = len(image_metadata)
    pending_images = sum(1 for img_id, meta in image_metadata.items() if meta['status'] == 'pending')
    labeled_images = len(labeled_dataset)
    total_annotations_received = sum(len(ann_list) for ann_list in labels_data.values())

    return jsonify({
        'total_images_uploaded': total_images,
        'images_pending_labeling': pending_images,
        'images_with_agreed_label': labeled_images,
        'total_annotations_received': total_annotations_received,
        'min_annotators_per_image': MIN_ANNOTATORS_PER_IMAGE,
        'model_trained_on_samples': len(labeled_dataset)
    }), 200

if __name__ == '__main__':
    app.run(debug=True, port=5000)

